#include <stdio.h>
#include <stdint.h>

// Function to calculate the combination formula
uint64_t combination(uint64_t n, uint64_t k, uint64_t p) {
    uint64_t result = 1;
    for (uint64_t i = 1; i <= k; i++) {
        result = (result * (n - i + 1)) % p;
        result = (result * modInverse(i, p)) % p;
    }
    return result;
}

// Function to calculate the modular inverse
uint64_t modInverse(uint64_t a, uint64_t p) {
    uint64_t t = 0;
    uint64_t newt = 1;
    uint64_t r = p;
    uint64_t newr = a;
    while (newr != 0) {
        uint64_t quotient = r / newr;
        uint64_t tmp = t - quotient * newt;
        t = newt;
        newt = tmp;
        tmp = r - quotient * newr;
        r = newr;
        newr = tmp;
    }
    if (r > 1) return -1;
    if (t < 0) t += p;
    return t;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        uint64_t n, k, p;
        scanf("%llu %llu %llu", &n, &k, &p);
        uint64_t sum = 0;
        for (uint64_t i = 0; i <= n; i++) {
            sum = (sum + combination(i + k - 1, k - 1, p)) % 1000003;
        }
        printf("%llu\n", sum);
    }
    return 0;
}

